local http = require "resty.http"

function proxy_request()
    local url = ngx.var.arg_url
    if not url then
        ngx.status = 400
        ngx.say("URL parameter is required")
        return
    end

    local httpc = http.new()
    local res, err = httpc:request_uri(url)
    if not res then
        ngx.status = 500
        ngx.say("Failed to fetch content: ", err)
        return
    end

    ngx.header["Content-Type"] = res.headers["content-type"]
    for k, v in pairs(res.headers) do
        if k ~= "content-type" and k ~= "content-length" then
            ngx.header[k] = v
        end
    end

    ngx.say(res.body)
end

